# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import sqlite3

app = Flask(__name__)
app.secret_key = 'your-secret-key'

def get_db():
    conn = sqlite3.connect('database.db')
    conn.row_factory = sqlite3.Row
    return conn

@app.route('/api/profile', methods=['POST'])
def update_profile():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401
    
    user_id = session['user_id']
    data = request.get_json()
    
    conn = get_db()
    cursor = conn.cursor()
    
    try:
        # Update email
        if 'email' in data:
            cursor.execute('UPDATE users SET email = ? WHERE id = ?', 
                          (data['email'], user_id))
        
        # Update password
        if 'password' in data:
            hashed = generate_password_hash(data['password'])
            cursor.execute('UPDATE users SET password_hash = ? WHERE id = ?', 
                          (hashed, user_id))
        
        # Update 2FA settings
        if 'two_factor_enabled' in data:
            cursor.execute('UPDATE users SET two_factor_enabled = ? WHERE id = ?', 
                          (data['two_factor_enabled'], user_id))
        
        conn.commit()
        return jsonify({'message': 'Profile updated successfully'})
    
    except Exception as e:
        conn.rollback()
        return jsonify({'error': 'Database error'}), 500
    finally:
        conn.close()